SQL:
SELECT CAST(COUNT(*) AS REAL) / 10 AS avg_production_per_year
FROM `production`
WHERE `model_year` BETWEEN 1971 AND 1980;

SELECT `Name`
FROM `City`
WHERE `Population` = (SELECT MAX(`Population`) FROM `City`);

SELECT `firstname`, `lastname`, `performance`
FROM `employee`
WHERE CAST(REPLACE(SUBSTR(salary, 4), ',', '') AS REAL) = (
      SELECT MIN(CAST(REPLACE(SUBSTR(salary, 4), ',', '') AS REAL)) FROM `employee`
);

SELECT
  (SELECT AVG(`list_movie_number`) FROM `lists` WHERE `user_id` = 8516503) AS avg_movies_in_lists,
  (SELECT COUNT(*) FROM `ratings` WHERE `user_id` = 8516503 AND `rating_score` = 5) AS count_rating_5;

SELECT COUNT(*)
FROM `Customers`
WHERE `City` = 'London';
